sql:
SELECT COUNT(*) AS film_count
FROM films
WHERE rating > 4;

SELECT f.title, fg.domestic_gross, fg.international_gross, fg.total_gross
FROM films f
JOIN film_financials fg ON f.film_id = fg.film_id;

SELECT f.film_id, f.title, ff.total_gross, ff.profit
FROM films AS f
INNER JOIN film_financials AS ff ON f.film_id = ff.film_id;

SELECT SUM(CAST(REPLACE(trim(total_gross, '$'), ',', '') AS REAL)) AS total_revenue 
FROM films 
WHERE strftime('%Y', release_date) = '2017';

SELECT user_id, COUNT(*) as number_of_ratings 
FROM film_ratings
GROUP BY user_id;

SELECT title, total_gross
FROM films
WHERE CAST(REPLACE(trim(total_gross, '$'), ',', '') AS REAL) = (
    SELECT MAX(CAST(REPLACE(trim(total_gross, '$'), ',', '') AS REAL))
    FROM films
);

SELECT title, rating
FROM films
ORDER BY rating DESC;

SELECT film_id, rating 
FROM film_ratings 
WHERE rating = (SELECT MAX(rating) FROM film_ratings);

